import React from "react";
import { ArrowLeft, Download } from "lucide-react";

export default function TransactionHistoryScreen({
  transactions,
  onSelectTransaction,
  onBack,
  darkMode
}) {
  return (
    <div className={`min-h-screen px-5 pt-6 pb-24 ${darkMode ? "bg-gray-900 text-white" : "bg-[#f4f6fb] text-gray-900"}`}>
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <button onClick={onBack}>
            <ArrowLeft className={`w-6 h-6 ${darkMode ? "text-white" : "text-gray-700"}`} />
          </button>
          <h1 className="text-xl font-semibold">
            Transactions
          </h1>
        </div>

        <button className="p-2 rounded-lg active:scale-95 transition">
          <Download className={`w-5 h-5 ${darkMode ? "text-white" : "text-gray-700"}`} />
        </button>
      </div>

      {/* List */}
      <div className="space-y-4">
        {transactions.map((tx) => (
          <button
            key={tx.id}
            onClick={() => onSelectTransaction(tx)}
            className={`w-full rounded-xl p-4 flex items-center justify-between active:scale-[0.99] transition ${
              darkMode ? "bg-gray-800 shadow-gray-700" : "bg-white shadow-sm"
            }`}
          >
            <div>
              <p className={`font-semibold ${darkMode ? "text-white" : "text-gray-900"}`}>
                {tx.type}
              </p>
              <p className={`text-sm ${darkMode ? "text-gray-400" : "text-gray-500"}`}>
                {tx.date}
              </p>
            </div>

            <p
              className={`font-semibold ${
                tx.type === "Deposit"
                  ? "text-emerald-600"
                  : darkMode
                  ? "text-red-400"
                  : "text-red-500"
              }`}
            >
              ₦{tx.amount.toLocaleString()}
            </p>
          </button>
        ))}
      </div>
    </div>
  );
}
